def validate_saml_response_structure(saml_response_xml):
    """
    Performs basic structural validation of the SAML Response XML.
    This is NOT a security validation (e.g., signature, replay).
    """
    try:
        root = ET.fromstring(saml_response_xml)

        # Check for Response element
        if root.tag != f"{SAML_PROTOCOL_NS}Response":
            logger.error(f"Invalid root element: {root.tag}")
            return False, "Invalid SAML Response root element."

        # Check for Status element
        status_element = root.find(f"{SAML_PROTOCOL_NS}Status")
        if status_element is None:
            logger.error("SAML Response missing Status element.")
            return False, "SAML Response missing Status element."

        status_code_element = status_element.find(f"{SAML_PROTOCOL_NS}StatusCode")
        if status_code_element is None:
            logger.error("SAML Response Status missing StatusCode element.")
            return False, "SAML Response Status missing StatusCode element."

        status_value = status_code_element.get("Value")
        if status_value != "urn:oasis:names:tc:SAML:2.0:status:Success":
            logger.error(f"SAML Response Status is not Success: {status_value}")
            return False, f"SAML Response Status is not Success: {status_value}"

        # Check for Assertion element
        assertion_element = root.find(f"{SAML_ASSERTION_NS}Assertion")
        if assertion_element is None:
            logger.error("SAML Response missing Assertion element.")
            return False, "SAML Response missing Assertion element."

        # Check for Subject and NameID within Assertion
        subject_element = assertion_element.find(f"{SAML_ASSERTION_NS}Subject")
        if subject_element is None:
            logger.error("SAML Assertion missing Subject element.")
            return False, "SAML Assertion missing Subject element."

        name_id_element = subject_element.find(f"{SAML_ASSERTION_NS}NameID")
        if name_id_element is None:
            logger.error("SAML Subject missing NameID element.")
            return False, "SAML Subject missing NameID element."

        return True, "SAML Response structure is valid."

    except ET.ParseError as e:
        logger.error(f"Failed to parse SAML XML: {e}")
        return False, f"Failed to parse SAML XML: {e}"
    except Exception as e:
        logger.error(f"An unexpected error occurred during SAML structure validation: {e}")
        return False, f"An unexpected error occurred: {e}"

def parse_saml_assertion(saml_response_xml):
    """
    Parses the SAML Assertion to extract NameID and attributes.
    """
    user_data = {
        "name_id": None,
        "attributes": {}
    }
    try:
        root = ET.fromstring(saml_response_xml)
        assertion_element = root.find(f"{SAML_ASSERTION_NS}Assertion")

        if assertion_element is None:
            logger.error("No Assertion found in SAML Response.")
            return None

        # Extract NameID
        name_id_element = assertion_element.find(f"{SAML_ASSERTION_NS}Subject/{SAML_ASSERTION_NS}NameID")
        if name_id_element is not None:
            user_data["name_id"] = name_id_element.text
            logger.debug(f"Extracted NameID: {user_data['name_id']}")

        # Extract Attributes
        attribute_statement_element = assertion_element.find(f"{SAML_ASSERTION_NS}AttributeStatement")
        if attribute_statement_element is not None:
            for attribute_element in attribute_statement_element.findall(f"{SAML_ASSERTION_NS}Attribute"):
                attr_name = attribute_element.get("Name")
                if attr_name:
                    attr_values = []
                    for attr_value_element in attribute_element.findall(f"{SAML_ASSERTION_NS}AttributeValue"):
                        attr_values.append(attr_value_element.text)
                    # For simplicity, store single values directly, multiple as list
                    user_data["attributes"][attr_name] = attr_values[0] if len(attr_values) == 1 else attr_values
                    logger.debug(f"Extracted Attribute: {attr_name} = {user_data['attributes'][attr_name]}")

        return user_data

    except ET.ParseError as e:
        logger.error(f"Failed to parse SAML XML during assertion extraction: {e}")
        return None
    except Exception as e:
        logger.error(f"An unexpected error occurred during SAML assertion parsing: {e}")
        return None

