@csrf_exempt
def saml_acs(request):
    """
    SAML Assertion Consumer Service (ACS) endpoint.
    Handles SAML POST responses from the IdP.
    """
    if request.method == 'POST':
        saml_response_b64 = request.POST.get('SAMLResponse')
        if not saml_response_b64:
            logger.error("No SAMLResponse found in POST data.")
            return render(request, 'saml_error.html', {'error': 'No SAMLResponse found.'}, status=400)

        try:
            saml_response_xml = base64.b64decode(saml_response_b64).decode('utf-8')
            logger.debug(f"Received SAML Response XML:\n{saml_response_xml}")
        except Exception as e:
            logger.error(f"Failed to decode SAMLResponse: {e}")
            return render(request, 'saml_error.html', {'error': 'Invalid SAMLResponse encoding.'}, status=400)

        # 1. Basic XML Structure Validation
        is_valid_structure, validation_message = validate_saml_response_structure(saml_response_xml)
        if not is_valid_structure:
            logger.error(f"SAML Response structural validation failed: {validation_message}")
            return render(request, 'saml_error.html', {'error': f'SAML Response structural validation failed: {validation_message}'}, status=400)

        # 2. Parse SAML Assertion
        user_data = parse_saml_assertion(saml_response_xml)
        if not user_data or not user_data.get("name_id"):
            logger.error("Failed to extract NameID or user attributes from SAML Assertion.")
            return render(request, 'saml_error.html', {'error': 'Failed to extract user information from SAML Assertion.'}, status=400)

        name_id = user_data["name_id"]
        attributes = user_data["attributes"]

        # 3. Authenticate and Create/Update Django User
        # In a real scenario, you might map SAML attributes to Django user fields.
        # For example, 'email' attribute to user.email, 'firstName' to user.first_name.
        # You might also use a custom authentication backend.

        # Example mapping:
        email = attributes.get("email", f"{name_id}@example.com") # Fallback email
        first_name = attributes.get("firstName", "")
        last_name = attributes.get("lastName", "")

        try:
            user, created = User.objects.get_or_create(username=name_id)
            if created:
                user.email = email
                user.first_name = first_name
                user.last_name = last_name
                user.set_unusable_password() # SAML users don't use Django passwords
                user.save()
                logger.info(f"Created new Django user: {name_id}")
            else:
                # Update user details if they change in IdP
                if user.email != email:
                    user.email = email
                if user.first_name != first_name:
                    user.first_name = first_name
                if user.last_name != last_name:
                    user.last_name = last_name
                user.save()
                logger.info(f"Updated existing Django user: {name_id}")

            # Log the user in
            # Note: authenticate() might not be strictly necessary if you're just
            # creating/getting the user and then logging them in directly.
            # However, if you had a custom SAML auth backend, it would be used here.
            user_auth = authenticate(request, username=user.username) # This might require a custom backend
            if user_auth is not None:
                login(request, user_auth)
                logger.info(f"User {name_id} successfully logged in via SAML.")
                return redirect(settings.LOGIN_REDIRECT_URL)
            else:
                logger.error(f"Failed to authenticate user {name_id} after SAML assertion.")
                return render(request, 'saml_error.html', {'error': 'Authentication failed after SAML processing.'}, status=500)

        except Exception as e:
            logger.error(f"Error creating/updating Django user or logging in: {e}")
            return render(request, 'saml_error.html', {'error': f'Internal server error during user provisioning: {e}'}, status=500)

    else:
        logger.warning("SAML ACS endpoint accessed with GET request.")
        return render(request, 'saml_error.html', {'error': 'SAML ACS endpoint only accepts POST requests.'}, status=405)

def saml_login_init(request):
    """
    Initiates the SAML SSO flow by redirecting to the IdP's SSO URL.
    """
    # In a real scenario, you might build a SAML AuthnRequest here.
    # For simplicity, we're just redirecting to the IdP's SSO URL.
    # The IdP is expected to know where to send the response (ACS_URL).
    return redirect(SAML_SP_CONFIG["IDP_SSO_URL"])

def saml_metadata(request):
    """
    Generates the SAML Service Provider metadata XML.
    """
    metadata_xml = f"""<?xml version="1.0"?>
<md:EntityDescriptor xmlns:md="urn:oasis:names:tc:SAML:2.0:metadata"
                     entityID="{SAML_SP_CONFIG['ENTITY_ID']}">
    <md:SPSSODescriptor protocolSupportEnumeration="urn:oasis:names:tc:SAML:2.0:protocol"
                        AuthnRequestsSigned="false" WantAssertionsSigned="false">
        <md:AssertionConsumerService Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
                                     Location="{SAML_SP_CONFIG['ACS_URL']}"
                                     index="1"/>
    </md:SPSSODescriptor>
</md:EntityDescriptor>"""
    return render(request, 'saml_metadata.xml', {'metadata_xml': metadata_xml}, content_type='application/xml')

